use std::collections::HashMap;

const FUZZY_MATCH_THRESHOLD: f64 = 0.85;
const MAX_RESULTS: usize = 50;
const TITLE_BOOST: f64 = 2.5;
const RECENCY_DECAY: f64 = 0.95;

pub fn rank_results(query: &str, candidates: &[Document]) -> Vec<RankedResult> {
    let mut scored: Vec<_> = candidates
        .iter()
        .filter_map(|doc| {
            let similarity = jaro_winkler(query, &doc.title);
            if similarity >= FUZZY_MATCH_THRESHOLD {
                let score = similarity * TITLE_BOOST
                    + doc.body_match_score
                    + recency_score(doc.updated_at, RECENCY_DECAY);
                Some(RankedResult { doc: doc.clone(), score })
            } else {
                None
            }
        })
        .collect();
    scored.sort_by(|a, b| b.score.partial_cmp(&a.score).unwrap());
    scored.truncate(MAX_RESULTS);
    scored
}
